// Random human-like delay: 0–18 minutes
// Prevents bot-like clockwork posting pattern
const delayMs = Math.floor(Math.random() * 18 * 60 * 1000);
await new Promise(r => setTimeout(r, delayMs));
return $input.all();

// Keep only articles < 35 minutes old
const item = $input.item.json;
const pub = new Date(item.pubDate || item.isoDate || Date.now());
if (Date.now() - pub.getTime() > 35 * 60 * 1000) return [];

const title = (item.title || '').replace(/ - [^-]+$/, '').trim();
const raw = item['content:encoded'] || item.content || item.summary || '';
const imgMatch = raw.match(/<img[^>]+src=["']([^"']+)["']/i);
const imageUrl = (imgMatch && imgMatch[1]) || (item.enclosure && item.enclosure.url) || '';
const body = raw.replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim().slice(0, 900);

return [{ json: { title, link: item.link || '', pubDate: pub.toISOString(), imageUrl, body } }];

const link = $('🔧 Parse & Age Filter').item.json.link;
const dup = $input.all().some(r => r.json.link === link || r.json.url === link);
if (dup) return [{ json: { skip: true } }];
return [{ json: { skip: false, ...$('🔧 Parse & Age Filter').item.json } }];

const raw = $input.item.json.content?.[0]?.text || '{}';
let ai;
try {
  ai = JSON.parse(raw.replace(/```json?\n?/g,'').replace(/```/g,'').trim());
} catch(e) {
  return [{ json: { skip: true, reason: 'parse_error' } }];
}

if (!ai.publish || ai.score < 7) {
  return [{ json: { skip: true, reason: 'low_score', score: ai.score } }];
}

// Rotate variant if Claude always returns 1
const forcedVariant = ai.variant || Math.floor(Math.random() * 3) + 1;

const src = $('🔍 Dedup Check').item.json;
return [{ json: {
  skip:           false,
  headline:       ai.headline        || src.title.toUpperCase(),
  highlight_text: ai.highlight_text  || '',
  content:        ai.content         || '',
  script:         ai.script          || ai.content || '',
  keywords:       (ai.keywords || []).join(','),
  source_tag:     ai.source_tag      || 'Tamil Nadu · News',
  theme:          ai.theme           || 'crime',
  variant:        forcedVariant,
  score:          ai.score,
  caption:        '📍 ' + (ai.source_tag || 'Tamil Nadu'),
  image_url:      src.imageUrl       || '',
  article_link:   src.link,
  pub_date:       src.pubDate
} }];

const d = $input.item.json;
const params = new URLSearchParams({
  headline:  d.headline       || '',
  img:       d.image_url      || '',
  caption:   d.caption        || '',
  highlight: d.highlight_text || '',
  content:   d.content        || '',
  keywords:  d.keywords       || '',
  source:    d.source_tag     || 'Tamil Nadu News',
  channel:   'Tamil Shorts',
  theme:     d.theme          || 'crime',
  variant:   String(d.variant || 1)
});
// ← Replace with your Cloudflare Pages URL
const BASE = 'https://YOUR-PROJECT.pages.dev/card-template.html';
return [{ json: { ...d, cardUrl: `${BASE}?${params.toString()}` } }];

// Convert binary PNG to base64 for Railway service
const pngB64 = $binary.cardPng.data;
return [{ json: {
  ...$json,
  pngBase64: pngB64
} }];

